params.script:
var dept = $ivr.getObject("clinicalDepartment");
var s2b = ["消化器内科","食道胃外科","大腸肛門器外科","肝胆膵外科","呼吸器外科"];
var isS2B = false;
for(var i=0;i<s2b.length;i++){if(dept===s2b[i]){isS2B=true;break;}}
$runner.setResult(isS2B?"S2B":"非S2B");

var dept = $ivr.getObject("clinicalDepartment");
var s2b = ["消化器内科","食道胃外科","大腸肛門器外科","肝胆膵外科","呼吸器外科"];
var isS2B = false;
for(var i=0;i<s2b.length;i++){if(dept===s2b[i]){isS2B=true;break;}}
$runner.setResult(isS2B?"S2B":"非S2B");

var phonetype = $ivr.getObject("phonetype");
var classification = $ivr.getObject("classification");
var isMobile = (phonetype === "携帯");
var result;
if(isMobile){
  if(classification==="予約") result="SMS_予約";
  else if(classification==="変更") result="SMS_変更";
  else result="SMS_キャンセル";
} else {
  result="NOSMS";
}
$runner.setResult(result);
